previewCss:
.darma-loader-darma-custom-121 {
  color: var(--loader-color, #2563eb);
width: 49px;
aspect-ratio: 1;
--c: no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color, #60a5fa));
background:
var(--c) 0% 50%,
var(--c) 50% 50%,
var(--c) 100% 50%;
background-size: 20% 100%;
animation: darma-loader-darma-custom-121-l1 1s infinite linear;
}
@keyframes darma-loader-darma-custom-121-l1 {
0% {background-size: 20% 100%,20% 100%,20% 100%}
33% {background-size: 20% 10% ,20% 100%,20% 100%}
50% {background-size: 20% 100%,20% 10% ,20% 100%}
66% {background-size: 20% 100%,20% 100%,20% 10% }
100%{background-size: 20% 100%,20% 100%,20% 100%}
}

